struct EvaporativeCrystallizerBalanceEngine: Sendable { func calculate(_ input: EvaporativeCrystallizerBalanceInput) throws -> EvaporativeCrystallizerBalanceResult { let v=[input.feedMassFlow,input.feedSoluteMassFraction,input.solventEvaporationFlow,input.motherLiquorSoluteMassFraction,input.crystalPurityFraction]; guard v.allSatisfy(\.isFinite) else { throw EvaporativeCrystallizerBalanceError.nonFiniteInput }; guard input.feedMassFlow>0 else { throw EvaporativeCrystallizerBalanceError.nonPositiveFeedFlow }; guard input.feedSoluteMassFraction>0,input.feedSoluteMassFraction<1,input.motherLiquorSoluteMassFraction>=0,input.motherLiquorSoluteMassFraction<1,input.crystalPurityFraction>0,input.crystalPurityFraction<=1 else { throw EvaporativeCrystallizerBalanceError.invalidFraction }; guard input.solventEvaporationFlow>=0,input.solventEvaporationFlow<input.feedMassFlow else { throw EvaporativeCrystallizerBalanceError.invalidEvaporationFlow }; let rem=input.feedMassFlow-input.solventEvaporationFlow; let sol=input.feedMassFlow*input.feedSoluteMassFraction; let den=input.crystalPurityFraction-input.motherLiquorSoluteMassFraction; guard den>0 else { throw EvaporativeCrystallizerBalanceError.infeasibleBalance }; let c=(sol-input.motherLiquorSoluteMassFraction*rem)/den; let l=rem-c; guard c>=0,l>=0 else { throw EvaporativeCrystallizerBalanceError.infeasibleBalance }; let cs=c*input.crystalPurityFraction; let r=cs/sol; let closure=c+l+input.solventEvaporationFlow; guard [rem,sol,c,l,cs,r,closure].allSatisfy(\.isFinite),r>=0,r<=1 else { throw EvaporativeCrystallizerBalanceError.numericalFailure }; return .init(crystalProductFlow:c,motherLiquorFlow:l,pureSoluteInCrystals:cs,soluteRecoveryFraction:r,totalMassClosure:closure,modelName:"Steady evaporative crystallizer mass balance",limitationDescription:"Assumes the evaporated stream is pure solvent and product compositions are specified.") } }
